package Java_Assignment;

public class Assignment_10_ifelseifelse {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
           int a=10;
           float b=20;
           double c=66.7;
           
           if(a==b)
           {
        	   System.out.println("The value a&b is passed");
           }
           
           else if(b>=c)
           {
        	   System.out.println("The value b&c is passed");
           }
           
           else
           {
        	   System.out.println("The value a,b,c are failed");
           }
	}

}
